import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../../utils/config";
import type { ToolPlugin } from "../manager";

// Knowledge Graph Types
export interface Entity {
  id: string;
  type: "concept" | "project" | "insight" | "person" | "unknown";
  name: string;
  description?: string | undefined;
  createdAt: number;
  updatedAt: number;
  occurrences: number;
}

export interface Relationship {
  id: string;
  sourceId: string;
  targetId: string;
  type: string;
  strength: number;
  createdAt: number;
  context?: string | undefined;
}

export interface KnowledgeGraph {
  entities: Record<string, Entity>;
  relationships: Record<string, Relationship>;
  lastUpdated: number;
}

// Allow test override of storage path
let storagePath: string | null = null;

export function _setStoragePathForTest(p: string | null) {
  storagePath = p;
}

function getStoragePath(): string {
  return storagePath ?? path.join(config.HISTORY_DIR, "knowledge_graph.json");
}

async function loadGraph(): Promise<KnowledgeGraph> {
  const file = getStoragePath();
  try {
    const content = await fs.readFile(file, "utf-8");
    return JSON.parse(content);
  } catch {
    return {
      entities: {},
      relationships: {},
      lastUpdated: Date.now(),
    };
  }
}

async function saveGraph(graph: KnowledgeGraph) {
  graph.lastUpdated = Date.now();
  const file = getStoragePath();
  const tmpFile = `${file}.tmp.${Date.now()}.${Math.random().toString(36).slice(2)}`;
  await fs.writeFile(tmpFile, JSON.stringify(graph, null, 2));
  await fs.rename(tmpFile, file); // Atomic on POSIX
}

function entityId(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

export const semanticMemoryPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "semantic_memory",
      description: "Manage semantic knowledge: store entities, relationships, and query the knowledge graph",
      parameters: {
        type: "object",
        properties: {
          action: {
            type: "string",
            enum: ["store_entity", "store_relation", "query_entity", "query_graph", "find_related"],
            description: "Action to perform on the knowledge graph",
          },
          name: {
            type: "string",
            description: "Entity name (for store_entity, query_entity)",
          },
          entityType: {
            type: "string",
            enum: ["concept", "project", "insight", "person", "unknown"],
            description: "Type of entity (for store_entity)",
          },
          description: {
            type: "string",
            description: "Description of the entity (for store_entity)",
          },
          source: {
            type: "string",
            description: "Source entity name (for store_relation)",
          },
          target: {
            type: "string",
            description: "Target entity name (for store_relation)",
          },
          relationType: {
            type: "string",
            description: "Relationship type, e.g., 'related_to', 'depends_on' (for store_relation)",
          },
          context: {
            type: "string",
            description: "Context where relationship was observed (for store_relation)",
          },
          searchTerm: {
            type: "string",
            description: "Search term for finding entities (for query_graph)",
          },
          limit: {
            type: "number",
            description: "Max results to return (default: 10)",
          },
        },
        required: ["action"],
      },
    },
  },

  execute: async (args: {
    action: "store_entity" | "store_relation" | "query_entity" | "query_graph" | "find_related";
    name?: string;
    entityType?: string;
    description?: string;
    source?: string;
    target?: string;
    relationType?: string;
    context?: string;
    searchTerm?: string;
    limit?: number;
  }) => {
    const now = Date.now();

    switch (args.action) {
      case "store_entity": {
        if (!args.name) return "Error: 'name' required for store_entity";
        const id = entityId(args.name);

        const graph = await loadGraph();
        const existing = graph.entities[id];

          type: args.relationType,
          strength: 1.0,
          createdAt: now,
          context: args.context,
        };

        await saveGraph(graph);
        return `Stored relation: "${args.source}" --[${args.relationType}]--> "${args.target}"`;
      }

      case "query_entity": {
        if (!args.name) return "Error: 'name' required for query_entity";
        const id = entityId(args.name);
        const graph = await loadGraph();
        const entity = graph.entities[id];

        if (!entity) return `No entity found: "${args.name}"`;

        const related = Object.values(graph.relationships).filter(
          r => r.sourceId === id || r.targetId === id
        );

        let output = `📌 Entity: ${entity.name}\n`;
        output += `Type: ${entity.type} | Mentions: ${entity.occurrences}\n`;
        if (entity.description) output += `Description: ${entity.description}\n`;
        output += `\n🔗 Relationships (${related.length}):\n`;

        for (const rel of related.slice(0, args.limit || 10)) {
          const otherId = rel.sourceId === id ? rel.targetId : rel.sourceId;
          const other = graph.entities[otherId];
          const direction = rel.sourceId === id ? "→" : "←";
          output += `  ${direction} [${rel.type}] ${other?.name || otherId}\n`;
        }

        return output;
      }

      case "query_graph": {
        const limit = Math.min(args.limit || 20, 50);
        const graph = await loadGraph();
        const entities = Object.values(graph.entities);

        if (entities.length === 0) {
          return "🫙 Knowledge graph is empty.";
        }

        let filtered = entities;
        if (args.searchTerm) {
          const term = args.searchTerm.toLowerCase();
          filtered = entities.filter(e => 
            e.name.toLowerCase().includes(term) ||
            e.description?.toLowerCase().includes(term) ||
            e.type.toLowerCase().includes(term)
          );
        }

        const recent = filtered
          .sort((a, b) => b.updatedAt - a.updatedAt)
          .slice(0, limit);

        let output = `🧠 Knowledge Graph (${recent.length} of ${entities.length} entities)\n`;
        output += "=".repeat(50) + "\n\n";

        for (const e of recent) {
          const date = new Date(e.updatedAt).toISOString().split("T")[0];
          output += `[${e.type}] ${e.name} (${e.occurrences} mentions, ${date})\n`;
          if (e.description) {
            output += `  ${e.description.substring(0, 80)}${e.description.length > 80 ? "..." : ""}\n`;
          }
          output += "\n";
        }

        return output;
      }

      case "find_related": {
        if (!args.name) return "Error: 'name' required for find_related";
        const id = entityId(args.name);
        const graph = await loadGraph();

        const visited = new Set<string>();
        const queue: { id: string; depth: number }[] = [{ id, depth: 0 }];
        const subgraph: string[] = [];

        while (queue.length > 0 && subgraph.length < (args.limit || 20)) {
          const current = queue.shift()!;
          if (visited.has(current.id)) continue;
          visited.add(current.id);
          subgraph.push(current.id);

          const neighbors = Object.values(graph.relationships)
            .filter(r => r.sourceId === current.id || r.targetId === current.id)
            .map(r => r.sourceId === current.id ? r.targetId : r.sourceId)
            .filter(nid => !visited.has(nid));

          for (const nid of neighbors) {
            if (current.depth < 2) {
              queue.push({ id: nid, depth: current.depth + 1 });
            }
          }
        }

        let output = `🕸️  Subgraph: "${args.name}" (depth 2)\n`;
        output += "=".repeat(40) + "\n\n";

        for (const nodeId of subgraph) {
          const entity = graph.entities[nodeId];
          if (entity) {
            output += `• ${entity.name} (${entity.type})\n`;
          }
        }

        return output;
      }

      default:
        return `Error: Unknown action "${args.action}"`;
    }
  },
};

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { semanticMemoryPlugin, _setStoragePathForTest } from "./semantic_memory";
import fs from "node:fs/promises";
import path from "node:path";
import os from "node:os";
import { config } from "../../utils/config";

describe("semanticMemoryPlugin", () => {
  let testStoragePath: string;

  beforeEach(async () => {
    // Create unique temp file for this test
    testStoragePath = path.join(
      os.tmpdir(),
      `knowledge_graph_test_${Date.now()}_${Math.random().toString(36).slice(2)}.json`
    );
    _setStoragePathForTest(testStoragePath);
  });

  afterEach(async () => {
    // Cleanup
    try {
      await fs.unlink(testStoragePath);
    } catch {}
    _setStoragePathForTest(null);
  });

  it("should store and query entities", async () => {
    const result = await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Test Concept",
      entityType: "concept",
      description: "A test concept for verification",
    });
    expect(result).toContain("Test Concept");
    expect(result).toContain("concept");
    expect(result).toContain("occurs: 1x");

    // Query it back
    const query = await semanticMemoryPlugin.execute({
      action: "query_entity",
      name: "Test Concept",
    });
    expect(query).toContain("Test Concept");
    expect(query).toContain("concept");
  });

  it("should track entity occurrences", async () => {
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Frequent Thought",
      entityType: "insight",
    });
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Frequent Thought",
      entityType: "insight",
    });
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Frequent Thought",
      entityType: "insight",
    });

    const query = await semanticMemoryPlugin.execute({
      action: "query_entity",
      name: "Frequent Thought",
    });
    expect(query).toContain("Mentions: 3");
  });

  it("should store and query relationships", async () => {
    await semanticMemoryPlugin.execute({
      action: "store_relation",
      source: "Memory System",
      target: "Knowledge Graph",
      relationType: "is_a",
      context: "Architectural insight",
    });

    const result = await semanticMemoryPlugin.execute({
      action: "query_entity",
      name: "Memory System",
    });
    expect(result).toContain("is_a");
    expect(result).toContain("Knowledge Graph");
  });

  it("should query the full graph", async () => {
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Alpha",
      entityType: "project",
    });
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Beta",
      entityType: "concept",
    });

    const graph = await semanticMemoryPlugin.execute({
      action: "query_graph",
      limit: 10,
    });
    expect(graph).toContain("Alpha");
    expect(graph).toContain("Beta");
    expect(graph).toContain("project");
    expect(graph).toContain("concept");
  });

  it("should search the graph", async () => {
    await semanticMemoryPlugin.execute({
      action: "store_entity",
      name: "Searchable Term",
      entityType: "insight",
      description: "Contains unique xyz789 token",
    });

    const result = await semanticMemoryPlugin.execute({
      action: "query_graph",
      searchTerm: "xyz789",
    });
    expect(result).toContain("Searchable Term");
    expect(result).toContain("xyz789");
  });

  it("should find related entities", async () => {
    await semanticMemoryPlugin.execute({
      action: "store_relation",
      source: "Axiom",
      target: "Semantic Memory",
      relationType: "created",
    });
    await semanticMemoryPlugin.execute({
      action: "store_relation",
      source: "Semantic Memory",
      target: "Knowledge Graph",
      relationType: "is_a",
    });

    const related = await semanticMemoryPlugin.execute({
      action: "find_related",
      name: "Axiom",
    });
    expect(related).toContain("Axiom");
    expect(related).toContain("Semantic Memory");
  });

  it("should handle missing entities", async () => {
    const result = await semanticMemoryPlugin.execute({
      action: "query_entity",
      name: "NonExistent",
    });
    expect(result).toContain("No entity found");
  });
});

